    public Object parseTransaction(Object transaction, Object... optionalArgs)
    {
        //
        //  deposit
        //      {
        //          "timestamp": 1485363039.18359,
        //          "id": 317,
        //          "currency": "BTC",
        //          "amount": 530.00000000
        //      }
        //
        //  withdrawal
        //      {
        //          "id": 403,
        //          "timestamp": 1485363466.868539,
        //          "currency": "BTC",
        //          "amount": 0.53000000,
        //          "status": 20
        //      }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeTimestamp(transaction, "timestamp");
        Object currencyId = this.safeString(transaction, "currency");
        Object statusId = this.safeString(transaction, "status");
        return new java.util.HashMap<String, Object>() {{
            put( "id", Btcalpha.this.safeString(transaction, "id") );
            put( "info", transaction );
            put( "timestamp", timestamp );
            put( "datetime", Btcalpha.this.iso8601(timestamp) );
            put( "network", null );
            put( "address", null );
            put( "addressTo", null );
            put( "addressFrom", null );
            put( "tag", null );
            put( "tagTo", null );
            put( "tagFrom", null );
            put( "currency", Btcalpha.this.safeCurrencyCode(currencyId, currency) );
            put( "amount", Btcalpha.this.safeNumber(transaction, "amount") );
            put( "txid", null );
            put( "type", null );
            put( "status", Btcalpha.this.parseTransactionStatus(statusId) );
            put( "comment", null );
            put( "internal", null );
            put( "fee", null );
            put( "updated", null );
        }};
    }

