    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // fetchClosedOrders / fetchOrder
        //     {
        //       "id": "923763073",
        //       "date": "1635451090368",
        //       "type": "sell",
        //       "pair": "XRP_USDT",
        //       "price": "1.00000000",
        //       "amount": "0.00000000",
        //       "status": "3",
        //       "amount_filled": "10.00000000",
        //       "amount_original": "10.0"
        //       "trades": [],
        //     }
        //
        // createOrder
        //     {
        //       "success": true,
        //       "date": "1635451754.497541",
        //       "type": "sell",
        //       "oid": "923776755",
        //       "price": "1.0",
        //       "amount": "10.0",
        //       "amount_filled": "0.0",
        //       "amount_original": "10.0",
        //       "trades": []
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(order, "pair");
        market = this.safeMarket(marketId, market, "_");
        Object symbol = Helpers.GetValue(market, "symbol");
        Object success = this.safeBool(order, "success", false);
        Object timestamp = null;
        if (Helpers.isTrue(success))
        {
            timestamp = this.safeTimestamp(order, "date");
        } else
        {
            timestamp = this.safeInteger(order, "date");
        }
        Object price = this.safeString(order, "price");
        Object remaining = this.safeString(order, "amount");
        Object filled = this.safeString(order, "amount_filled");
        Object amount = this.safeString(order, "amount_original");
        Object status = this.parseOrderStatus(this.safeString(order, "status"));
        Object id = this.safeStringN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("oid", "id", "order")));
        Object trades = this.safeValue(order, "trades");
        Object side = this.safeString2(order, "my_side", "type");
        final Object finalTimestamp = timestamp;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "clientOrderId", null );
            put( "datetime", Btcalpha.this.iso8601(finalTimestamp) );
            put( "timestamp", finalTimestamp );
            put( "status", status );
            put( "symbol", symbol );
            put( "type", "limit" );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", side );
            put( "price", price );
            put( "triggerPrice", null );
            put( "cost", null );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", remaining );
            put( "trades", trades );
            put( "fee", null );
            put( "info", order );
            put( "lastTradeTimestamp", null );
            put( "average", null );
        }}, market);
    }

    /**
     * @method
     * @name btcalpha#createOrder
     * @see https://btc-alpha.github.io/api-docs/#create-order
     * @description create a trade order
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount2, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object amount3 = amount2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object amount = amount3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(type, "market")))
            {
                throw new InvalidOrder((String)Helpers.add(this.id, " only limits orders are supported")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object finalAmount = this.amountToPrecision(symbol, amount);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "pair", Helpers.GetValue(market, "id") );
                put( "type", side );
                put( "amount", finalAmount );
                put( "price", Btcalpha.this.priceToPrecision(symbol, price) );
            }};
            Object response = (this.privatePostOrder(this.extend(request, parameters))).join();
            if (!Helpers.isTrue(Helpers.GetValue(response, "success")))
            {
                throw new InvalidOrder((String)Helpers.add(Helpers.add(this.id, " "), this.json(response))) ;
            }
            Object order = this.parseOrder(response, market);
            Object orderAmount = String.valueOf(Helpers.GetValue(order, "amount"));
            amount = ((Helpers.isTrue(Precise.stringGt(orderAmount, "0")))) ? Helpers.GetValue(order, "amount") : amount;
            Helpers.addElementToObject(order, "amount", this.parseNumber(amount));
            return order;
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

