    {
        return this.milliseconds();
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object query = this.urlencode(this.keysort(this.omit(parameters, this.extractParams(path))));
        Object url = Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "rest"), "/");
        if (Helpers.isTrue(!Helpers.isEqual(path, "charts/{pair}/{type}/chart/")))
        {
            url = Helpers.add(url, "v1/");
        }
        url = Helpers.add(url, this.implodeParams(path, parameters));
        headers = new java.util.HashMap<String, Object>() {{
            put( "Accept", "application/json" );
        }};
        if (Helpers.isTrue(Helpers.isEqual(api, "public")))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(query)))
            {
                url = Helpers.add(url, Helpers.add("?", query));
            }
        } else
        {
            this.checkRequiredCredentials();
            Object payload = this.apiKey;
            if (Helpers.isTrue(Helpers.isEqual(method, "POST")))
            {
                Helpers.addElementToObject(headers, "Content-Type", "application/x-www-form-urlencoded");
                body = query;
                payload = Helpers.add(payload, body);
            } else if (Helpers.isTrue(Helpers.getArrayLength(query)))
            {
                url = Helpers.add(url, Helpers.add("?", query));
            }
            Helpers.addElementToObject(headers, "X-KEY", this.apiKey);
            Helpers.addElementToObject(headers, "X-SIGN", this.hmac(this.encode(payload), this.encode(this.secret), sha256()));
            Helpers.addElementToObject(headers, "X-NONCE", String.valueOf(this.nonce()));
        }
        final Object finalUrl = url;
        final Object finalMethod = method;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", finalMethod );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object code, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        if (Helpers.isTrue(Helpers.isEqual(response, null)))
        {
            return null;  // fallback to default error handler
        }
        //
        //     {"date":1570599531.4814300537,"error":"Out of balance -9.99243661 BTC"}
        //
        Object error = this.safeString(response, "error");
        if (Helpers.isTrue(!Helpers.isEqual(error, null)))
        {
            Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), error, feedback);
            this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), error, feedback);
            throw new ExchangeError((String)feedback) ;
        }
        return null;
    }
